namespace SyncroBE.Infrastructure.Services
{
    public class PdfService : IPdfService
    {
        public async Task<string> GenerateAccountMovementReportPdfCopy(ClientAccountDto account, DateTime? startDate, DateTime? endDate)
        {
            string templateFileContent;

            Assembly executingAssembly = Assembly.GetExecutingAssembly();

            //Ubica y lee el nombre de la plantilla HTML
            string htmlFileName = "Templates\\ClientAccount.html";
            string filePath = Path.Combine(Path.GetDirectoryName(executingAssembly.Location), htmlFileName);
            using (var reader = new StreamReader(filePath, Encoding.UTF8))
            {
                templateFileContent = reader.ReadToEnd();
            }

            HtmlDocument htmlDocument = new HtmlDocument();
            htmlDocument.LoadHtml(templateFileContent);
            HtmlNode htmlNode = htmlDocument.DocumentNode.SelectSingleNode("//div");

            if (htmlNode == null)
            {
                return string.Empty;
            }

            string headerHtmlContent = GetClientAccountHeaderDetails(account);
            string bodyHtmlContent = GetClientAccountBodyDetails(account);
            string bottomHtmlContent = GetClientAccountBottomDetails(account);
            htmlNode.InnerHtml = headerHtmlContent + bodyHtmlContent + bottomHtmlContent;

            string updateHtml = htmlDocument.DocumentNode.OuterHtml;

            return updateHtml;

            //Metodos locales

            /*-------------------------------------------Contenido de pdf-------------------------------------------*/

            // Header
            string GetClientAccountHeaderDetails(ClientAccountDto account)
            {
                string htmlHeaderDetails = $@"<div class=""px-14 py-6"">
                <table class=""w-full border-collapse border-spacing-0"">
                    <tbody>
                        <tr>
                            <td class=""w-full align-top"">
                                <div>
                                    <img src=""data:image/png;base64,""
                                         class=""h-12""
                                         style=""height: 150px; width: 150px;""/>
                                </div>
                            </td>

                            <td class=""align-top"">
                                <div class=""text-sm"">
                                    <table class=""border-collapse border-spacing-0"">
                                        <tbody>
                                            <tr>
                                                <td class=""border-r pr-4"">
                                                    <div>
                                                        <p class=""whitespace-nowrap text-slate-400 text-right"">Fecha de emisión</p>
                                                        <p class=""whitespace-nowrap font-bold text-main text-right"">{DateTime.Now.Date.ToShortDateString()}</p>
                                                    </div>
                                                </td>
                                                <td class=""pl-4"">
                                                    <div>
                                                        <p class=""whitespace-nowrap text-slate-400 text-right"">Cuenta #</p>
                                                        <p class=""whitespace-nowrap font-bold text-main text-right"">{account.ClientAccountNumber}</p>
                                                    </div>
                                                </td>
                                            </tr>
                                        </tbody>
                                    </table>
                                </div>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>

            <div class=""px-14 py-6 text-sm details-section"">
            <section>
                <table class=""w-full border-collapse border-spacing-0"">
                    <tbody>
                        <tr>
                            <td class=""w-1/2 align-top"">
                                <div class=""text-sm text-neutral-600"">
                                    <p class=""font-bold"">Detalles de cuenta</p>
                                    <p>Cliente: {account.CustomerName}</p>
                                    <p>Fecha de apetura: {account.ClientAccountOpeningDate.ToShortDateString()}</p>
                                    <p>Estado: {VerifyClientAccountStatus(account.ClientAccountStatus)}</p>
                                    <p>Periodo abarcado: {(startDate != null || endDate != null? $"{startDate.Value.ToShortDateString()} - {endDate.Value.ToShortDateString()}" : $"Todo el tiempo")}</p>
                                </div>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </section>
            <section>
                <table class=""w-full border-collapse border-spacing-0"">
                    <tbody>
                        <tr>
                            <td class=""w-1/2 align-top"">
                                <div class=""text-sm text-neutral-600"">
                                    <p class=""font-bold"">Resumen financiero</p>
                                    <p>Limite de credito: ₡{account.ClientAccountCreditLimit}</p>
                                    <p>Saldo actual: ₡{account.ClientAccountCurrentBalance}</p>
                                    <p>Crédito disponible: ₡{(account.ClientAccountCreditLimit - account.ClientAccountCurrentBalance)}</p>
                                    <p>Tasa de interes: {account.ClientAccountInterestRate}%</p>
                                </div>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </section>
            </div>";
                return htmlHeaderDetails;
            }

            // Body
            string GetClientAccountBodyDetails(ClientAccountDto account)
            {
                int counter = 1;
                StringBuilder htmlBodyDetails = new StringBuilder();
                htmlBodyDetails.Append(@"
                    <div class=""px-14 py-10 text-sm text-neutral-700"">
                    <table class=""w-full border-collapse border-spacing-0"">
                    <thead>
                        <tr>
                            <td class=""border-b-2 border-main pb-3 pl-3 font-bold text-main"">Item</td>
                            <td class=""border-b-2 border-main pb-3 pl-2 font-bold text-main"">Fecha</td>
                            <td class=""border-b-2 border-main pb-3 pl-2 font-bold text-main"">Tipo</td>
                            <td class=""border-b-2 border-main pb-3 pl-2 text-center font-bold text-main"">Monto</td>
                            <td class=""border-b-2 border-main pb-3 pl-2 text-center font-bold text-main"">Saldo</td>
                        </tr>
                    </thead>
                    <tbody>");
                foreach (ClientAccountMovementDto m in account.Movements)
                {
                    htmlBodyDetails.Append($@"
                        <tr>
                            <td class=""border-b py-3 pl-3"">{counter++}</td>
                            <td class=""border-b py-3 pl-2"">{m.ClientAccountMovementDate.ToShortDateString()}</td>
                            <td class=""border-b py-3 pl-2"">{VerifyMovementType(m.ClientAccountMovementType)}</td>
                            <td class=""border-b py-3 pl-2 text-right"">₡{m.ClientAccountMovementAmount}</td>
                            <td class=""border-b py-3 pl-2 pr-3 text-right"">₡{m.ClientAccountMovementNewBalance}</td>
                        </tr>
                ");
                }
                htmlBodyDetails.Append($@"                        
                    </tbody>
                </table>
            </div>");
                return htmlBodyDetails.ToString();
            }

            // Footer
            string GetClientAccountBottomDetails(ClientAccountDto account)
            {
                string htmlBottomDetails = $@"
            <div class=""px-14 text-sm text-neutral-700"">
                <p class=""text-main font-bold"">Condiciones y Terminos</p>
                <p>
                    {account.ClientAccountConditions}
                </p>
            </div>

                <footer class=""fixed bottom-0 left-0 bg-slate-100 w-full text-neutral-600 text-center text-xs py-3"">
                    Syncro
                    <span class=""text-slate-300 px-2"">|</span>
                    All rights reserved
                </footer>";
                return htmlBottomDetails;
            }

            string VerifyClientAccountStatus(string status)
            {
                string value = "Sin estado";
                switch(status)
                {
                    case "active":
                        value = "Activa";
                        break;
                    case "suspended":
                        value = "Suspendida";
                        break;
                    case "closed":
                        value = "Cerrada";
                        break;
                    default:
                        break;
                }
                return value;
            }

            string VerifyMovementType(string type)
            {
                string value = "Sin definir";
                switch (type)
                {
                    case "debit":
                        value = "Debito";
                        break;
                    case "credit":
                        value = "Credito";
                        break;
                    default:
                        break;
                }
                return value;
            }
        }

        public async Task<string> GenerateQuotePdfCopy(QuoteDto quote)
        {
            string templateFileContent;

            Assembly executingAssembly = Assembly.GetExecutingAssembly();

            //Ubica y lee el nombre de la plantilla HTML
            string htmlFileName = "Templates\\Quote.html";
            string filePath = Path.Combine(Path.GetDirectoryName(executingAssembly.Location), htmlFileName);
            using (var reader = new StreamReader(filePath, Encoding.UTF8))
            {
                templateFileContent = reader.ReadToEnd();
            }

            HtmlDocument htmlDocument = new HtmlDocument();
            htmlDocument.LoadHtml(templateFileContent);
            HtmlNode htmlNode = htmlDocument.DocumentNode.SelectSingleNode("//div");

            if(htmlNode == null)
            {
                return string.Empty;
            }

            string headerHtmlContent = GetQuoteHeaderDetails(quote);
            string bodyHtmlContent = GetQuoteBodyDetails(quote);
            string bottomHtmlContent = GetQuoteBottomDetails(quote);
            htmlNode.InnerHtml = headerHtmlContent + bodyHtmlContent + bottomHtmlContent;

            string updateHtml = htmlDocument.DocumentNode.OuterHtml;

            return updateHtml;

            //Metodos locales

            /*-------------------------------------------Contenido de cotizacion-------------------------------------------*/

            // Header
            string GetQuoteHeaderDetails(QuoteDto quote)
            {
                string htmlHeaderDetails = $@"<div class=""px-14 py-6"">
                <table class=""w-full border-collapse border-spacing-0"">
                    <tbody>
                        <tr>
                            <td class=""w-full align-top"">
                                <div>
                                     <img src=""data:image/png;base64,""
                                         class=""h-12""
                                         style=""height: 150px; width: 150px""/>
                                </div>
                            </td>

                            <td class=""align-top"">
                                <div class=""text-sm"">
                                    <table class=""border-collapse border-spacing-0"">
                                        <tbody>
                                            <tr>
                                                <td class=""border-r pr-4"">
                                                    <div>
                                                        <p class=""whitespace-nowrap text-slate-400 text-right"">Fecha de emisión</p>
                                                        <p class=""whitespace-nowrap font-bold text-main text-right"">{quote.QuoteDate.Date.ToShortDateString()}</p>
                                                    </div>
                                                </td>
                                                <td class=""pl-4"">
                                                    <div>
                                                        <p class=""whitespace-nowrap text-slate-400 text-right"">Cotizacion #</p>
                                                        <p class=""whitespace-nowrap font-bold text-main text-right"">{quote.QuoteNumber}</p>
                                                    </div>
                                                </td>
                                            </tr>
                                        </tbody>
                                    </table>
                                </div>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>

            <div class=""px-14 py-6 text-sm"">
                <table class=""w-full border-collapse border-spacing-0"">
                    <tbody>
                        <tr>
                            <td class=""w-1/2 align-top"">
                                <div class=""text-sm text-neutral-600"">
                                    <p class=""font-bold"">Detalles de Cotización</p>
                                    <p>Cliente: {quote.ClientName}</p>
                                    <p>Cotizador: {quote.UserName}</p>
                                    <p>Valido hasta: {quote.QuoteValidTil.Date.ToShortDateString()}</p>
                                </div>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>";
                return htmlHeaderDetails;
            }

            // Body
            string GetQuoteBodyDetails(QuoteDto quote)
            {
                int counter = 1;
                StringBuilder htmlBodyDetails = new StringBuilder();
                htmlBodyDetails.Append(@"
                    <div class=""px-14 py-10 text-sm text-neutral-700"">
                    <table class=""w-full border-collapse border-spacing-0"">
                    <thead>
                        <tr>
                            <td class=""border-b-2 border-main pb-3 pl-3 font-bold text-main"">Item</td>
                            <td class=""border-b-2 border-main pb-3 pl-2 font-bold text-main"">Descripción</td>
                            <td class=""border-b-2 border-main pb-3 pl-2 text-right font-bold text-main"">Cantidad</td>
                            <td class=""border-b-2 border-main pb-3 pl-2 text-center font-bold text-main"">Precio Unitario</td>
                            <td class=""border-b-2 border-main pb-3 pl-2 text-center font-bold text-main"">Subtotal</td>
                        </tr>
                    </thead>
                    <tbody>");
                foreach (QuoteDetailDto qd in quote.QuoteDetails)
                {
                    htmlBodyDetails.Append($@"
                        <tr>
                            <td class=""border-b py-3 pl-3"">{counter++}</td>
                            <td class=""border-b py-3 pl-2"">{qd.ProductName}</td>
                            <td class=""border-b py-3 pl-2 text-right"">{qd.Quantity}</td>
                            <td class=""border-b py-3 pl-2 text-right"">₡{qd.UnitPrice}</td>
                            <td class=""border-b py-3 pl-2 pr-3 text-right"">₡{qd.LineTotal}</td>
                        </tr>
                ");
                }
                htmlBodyDetails.Append($@"                        
                          <tr>
                            <td colspan=""7"">
                                <table class=""w-full border-collapse border-spacing-0"">
                                    <tbody>
                                        <tr>
                                            <td class=""w-full""></td>
                                            <td>
                                                <table class=""w-full border-collapse border-spacing-0"">
                                                    <tbody>
                                                        <tr>
                                                            <td class=""border-b p-3"">
                                                                <div class=""whitespace-nowrap text-slate-400"">Subtotal:</div>
                                                            </td>
                                                            <td class=""border-b p-3 text-right"">
                                                                <div class=""whitespace-nowrap font-bold text-main"">₡{quote.QuoteTotal}</div>
                                                            </td>
                                                        </tr>
                                                        <tr>
                                                            <td class=""p-3"">
                                                                <div class=""whitespace-nowrap text-slate-400"">Descuentos:</div>
                                                            </td>
                                                            <td class=""p-3 text-right"">
                                                                <div class=""whitespace-nowrap font-bold text-main"">{(quote.QuoteDiscountApplied ? quote.QuoteDiscountPercentage : 0)}%</div>
                                                            </td>
                                                        </tr>
                                                        </br >
                                                        <tr>
                                                            <td class=""bg-main p-3"">
                                                                <div class=""whitespace-nowrap font-bold text-white"">Total:</div>
                                                            </td>
                                                            <td class=""bg-main p-3 text-right"">
                                                                <div class=""whitespace-nowrap font-bold text-white"">₡{Math.Round(quote.QuoteTotal - (quote.QuoteTotal * ((decimal)quote.QuoteDiscountPercentage / 100)), 2)}</div>
                                                            </td>
                                                        </tr>
                                                    </tbody>
                                                </table>
                                            </td>
                                        </tr>
                                    </tbody>
                                </table>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>");
                return htmlBodyDetails.ToString();
            }

            // Footer
            string GetQuoteBottomDetails(QuoteDto quote)
            {
                string htmlBottomDetails = $@"
            <div class=""px-14 text-sm text-neutral-700"">
                <p class=""text-main font-bold"">Condiciones y Terminos</p>
                <p>
                    {quote.QuoteConditions}
                </p>
            </div>

            <div class=""px-14 py-10 text-sm text-neutral-700"">
                <p class=""text-main font-bold"">Observaciones</p>
                <p class=""italic"">
                    {quote.QuoteRemarks}
                </p>
                </div>

                <footer class=""fixed bottom-0 left-0 bg-slate-100 w-full text-neutral-600 text-center text-xs py-3"">
                    Syncro
                    <span class=""text-slate-300 px-2"">|</span>
                    All rights reserved
                </footer>";
                return htmlBottomDetails;
            }
        }

        /*-------------------------------------------Contenido de Factura Electrónica-------------------------------------------*/

        public async Task<string> GenerateInvoicePdfHtml(Invoice invoice, CompanyConfig emisor, Purchase purchase, Client client)
        {
            string templateFileContent;

            Assembly executingAssembly = Assembly.GetExecutingAssembly();

            string htmlFileName = "Templates\\Invoice.html";
            string filePath = Path.Combine(Path.GetDirectoryName(executingAssembly.Location), htmlFileName);
            using (var reader = new StreamReader(filePath, Encoding.UTF8))
            {
                templateFileContent = reader.ReadToEnd();
            }

            HtmlDocument htmlDocument = new HtmlDocument();
            htmlDocument.LoadHtml(templateFileContent);
            HtmlNode htmlNode = htmlDocument.DocumentNode.SelectSingleNode("//div");

            if (htmlNode == null)
            {
                return string.Empty;
            }

            string headerHtml = GetInvoiceHeaderDetails(invoice, emisor);
            string clientHtml = GetInvoiceClientDetails(invoice, emisor, client);
            string bodyHtml = GetInvoiceBodyDetails(purchase, invoice);
            string bottomHtml = GetInvoiceBottomDetails(invoice);
            htmlNode.InnerHtml = headerHtml + clientHtml + bodyHtml + bottomHtml;

            string updateHtml = htmlDocument.DocumentNode.OuterHtml;
            return updateHtml;
        }

        private string GetInvoiceHeaderDetails(Invoice invoice, CompanyConfig emisor)
        {
            var docTypeName = invoice.DocumentType switch
            {
                "01" => "FACTURA ELECTRÓNICA",
                "03" => "NOTA DE CRÉDITO ELECTRÓNICA",
                "04" => "TIQUETE ELECTRÓNICO",
                _ => "COMPROBANTE ELECTRÓNICO"
            };

            var statusClass = invoice.HaciendaStatus switch
            {
                "accepted" => "bg-green-50 text-green-700",
                "rejected" => "bg-red-50 text-red-700",
                _ => "bg-yellow-50 text-yellow-700"
            };

            var statusText = invoice.HaciendaStatus switch
            {
                "accepted" => "ACEPTADA",
                "rejected" => "RECHAZADA",
                "sent" => "ENVIADA",
                "pending" => "PENDIENTE",
                "error" => "ERROR",
                _ => invoice.HaciendaStatus?.ToUpper() ?? "DESCONOCIDO"
            };

            string htmlHeaderDetails = $@"<div class=""px-14 py-6"">
                <table class=""w-full border-collapse border-spacing-0"">
                    <tbody>
                        <tr>
                            <td class=""w-full align-top"">
                                <div>
                                    <p class=""font-bold text-main"" style=""font-size: 1.25rem;"">{emisor.CommercialName ?? emisor.CompanyName}</p>
                                    <p class=""text-sm text-neutral-600"">{emisor.CompanyName}</p>
                                    <p class=""text-sm text-neutral-600"">Cédula: {emisor.IdNumber}</p>
                                    <p class=""text-sm text-neutral-600"">{emisor.Email}</p>
                                </div>
                            </td>

                            <td class=""align-top"">
                                <div class=""text-sm"">
                                    <table class=""border-collapse border-spacing-0"">
                                        <tbody>
                                            <tr>
                                                <td class=""border-r pr-4"">
                                                    <div>
                                                        <p class=""whitespace-nowrap text-slate-400 text-right"">Fecha de emisión</p>
                                                        <p class=""whitespace-nowrap font-bold text-main text-right"">{invoice.EmissionDate?.ToString("dd/MM/yyyy HH:mm") ?? "N/A"}</p>
                                                    </div>
                                                </td>
                                                <td class=""pl-4"">
                                                    <div>
                                                        <p class=""whitespace-nowrap text-slate-400 text-right"">{docTypeName}</p>
                                                        <p class=""whitespace-nowrap font-bold text-main text-right"">{invoice.ConsecutiveNumber}</p>
                                                    </div>
                                                </td>
                                            </tr>
                                        </tbody>
                                    </table>
                                    <div style=""margin-top: 8px; text-align: right;"">
                                        <span class=""{statusClass}"" style=""padding: 2px 8px; border-radius: 4px; font-weight: bold; font-size: 0.75rem;"">{statusText}</span>
                                    </div>
                                </div>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>";
            return htmlHeaderDetails;
        }

        private string GetInvoiceClientDetails(Invoice invoice, CompanyConfig emisor, Client client)
        {
            var condicionVenta = invoice.SaleCondition switch
            {
                "01" => "Contado",
                "02" => "Crédito",
                "03" => "Consignación",
                _ => invoice.SaleCondition ?? "N/A"
            };

            var medioPago = invoice.PaymentMethodCode switch
            {
                "01" => "Efectivo",
                "02" => "Tarjeta",
                "03" => "Cheque",
                "04" => "Transferencia / SINPE",
                _ => invoice.PaymentMethodCode ?? "N/A"
            };

            string htmlClientDetails = $@"
            <div class=""px-14 py-6 text-sm"">
                <table class=""w-full border-collapse border-spacing-0"">
                    <tbody>
                        <tr>
                            <td class=""w-1/2 align-top"">
                                <div class=""text-sm text-neutral-600"">
                                    <p class=""font-bold text-main"">Emisor</p>
                                    <p>{emisor.CompanyName}</p>
                                    <p>Cédula: {emisor.IdNumber}</p>
                                    <p>{emisor.OtherAddress}</p>
                                    <p>{emisor.Email}</p>
                                </div>
                            </td>
                            <td class=""w-1/2 align-top"">
                                <div class=""text-sm text-neutral-600"">
                                    <p class=""font-bold text-main"">Receptor</p>
                                    <p>{client.ClientName}</p>
                                    <p>Cédula: {client.ClientId}</p>
                                    <p>{client.ExactAddress ?? ""}</p>
                                    <p>{client.ClientEmail ?? ""}</p>
                                </div>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>

            <div class=""px-14 text-sm text-neutral-600"">
                <table class=""border-collapse border-spacing-0"">
                    <tbody>
                        <tr>
                            <td class=""pr-4""><span class=""text-slate-400"">Clave:</span> <span style=""font-size: 0.7rem;"">{invoice.Clave}</span></td>
                        </tr>
                        <tr>
                            <td class=""pr-4""><span class=""text-slate-400"">Condición de venta:</span> {condicionVenta}</td>
                            <td class=""pl-4""><span class=""text-slate-400"">Medio de pago:</span> {medioPago}</td>
                            <td class=""pl-4""><span class=""text-slate-400"">Moneda:</span> {invoice.CurrencyCode ?? "CRC"}</td>
                        </tr>
                    </tbody>
                </table>
            </div>";
            return htmlClientDetails;
        }

        private string GetInvoiceBodyDetails(Purchase purchase, Invoice invoice)
        {
            int counter = 1;
            StringBuilder htmlBodyDetails = new StringBuilder();
            htmlBodyDetails.Append(@"
                    <div class=""px-14 py-10 text-sm text-neutral-700"">
                    <table class=""w-full border-collapse border-spacing-0"">
                    <thead>
                        <tr>
                            <td class=""border-b-2 border-main pb-3 pl-3 font-bold text-main"">Item</td>
                            <td class=""border-b-2 border-main pb-3 pl-2 font-bold text-main"">Descripción</td>
                            <td class=""border-b-2 border-main pb-3 pl-2 text-right font-bold text-main"">Cantidad</td>
                            <td class=""border-b-2 border-main pb-3 pl-2 text-center font-bold text-main"">Precio Unitario</td>
                            <td class=""border-b-2 border-main pb-3 pl-2 text-center font-bold text-main"">Subtotal</td>
                        </tr>
                    </thead>
                    <tbody>");

            foreach (var sd in purchase.SaleDetails)
            {
                htmlBodyDetails.Append($@"
                        <tr>
                            <td class=""border-b py-3 pl-3"">{counter++}</td>
                            <td class=""border-b py-3 pl-2"">{sd.ProductName}</td>
                            <td class=""border-b py-3 pl-2 text-right"">{sd.Quantity}</td>
                            <td class=""border-b py-3 pl-2 text-right"">₡{sd.UnitPrice:N2}</td>
                            <td class=""border-b py-3 pl-2 pr-3 text-right"">₡{sd.LineTotal:N2}</td>
                        </tr>
                ");
            }

            // Totals section
            htmlBodyDetails.Append($@"
                        <tr>
                            <td colspan=""5"">
                                <table class=""w-full border-collapse border-spacing-0"">
                                    <tbody>
                                        <tr>
                                            <td class=""w-full""></td>
                                            <td>
                                                <table class=""w-full border-collapse border-spacing-0"">
                                                    <tbody>
                                                        <tr>
                                                            <td class=""border-b p-3"">
                                                                <div class=""whitespace-nowrap text-slate-400"">Subtotal:</div>
                                                            </td>
                                                            <td class=""border-b p-3 text-right"">
                                                                <div class=""whitespace-nowrap font-bold text-main"">₡{purchase.Subtotal:N2}</div>
                                                            </td>
                                                        </tr>");

            if (purchase.PurchaseDiscountApplied && purchase.PurchaseDiscountPercentage > 0)
            {
                htmlBodyDetails.Append($@"
                                                        <tr>
                                                            <td class=""border-b p-3"">
                                                                <div class=""whitespace-nowrap text-slate-400"">Descuento ({purchase.PurchaseDiscountPercentage}%):</div>
                                                            </td>
                                                            <td class=""border-b p-3 text-right"">
                                                                <div class=""whitespace-nowrap font-bold text-main"">-₡{Math.Round(purchase.Subtotal * purchase.PurchaseDiscountPercentage / 100m, 2):N2}</div>
                                                            </td>
                                                        </tr>");
            }

            if (purchase.TaxPercentage > 0)
            {
                htmlBodyDetails.Append($@"
                                                        <tr>
                                                            <td class=""border-b p-3"">
                                                                <div class=""whitespace-nowrap text-slate-400"">IVA ({purchase.TaxPercentage}%):</div>
                                                            </td>
                                                            <td class=""border-b p-3 text-right"">
                                                                <div class=""whitespace-nowrap font-bold text-main"">₡{purchase.TaxAmount:N2}</div>
                                                            </td>
                                                        </tr>");
            }

            htmlBodyDetails.Append($@"
                                                        <tr>
                                                            <td class=""bg-main p-3"">
                                                                <div class=""whitespace-nowrap font-bold text-white"">Total:</div>
                                                            </td>
                                                            <td class=""bg-main p-3 text-right"">
                                                                <div class=""whitespace-nowrap font-bold text-white"">₡{purchase.Total:N2}</div>
                                                            </td>
                                                        </tr>
                                                    </tbody>
                                                </table>
                                            </td>
                                        </tr>
                                    </tbody>
                                </table>
                            </td>
                        </tr>
                    </tbody>
                </table>
            </div>");
            return htmlBodyDetails.ToString();
        }

        private string GetInvoiceBottomDetails(Invoice invoice)
        {
            var referenceSection = "";
            if (!string.IsNullOrEmpty(invoice.ReferenceDocumentClave))
            {
                referenceSection = $@"
                <div class=""px-14 text-sm text-neutral-700"">
                    <p class=""text-main font-bold"">Documento de Referencia</p>
                    <p>Clave: {invoice.ReferenceDocumentClave}</p>
                    <p>Razón: {invoice.ReferenceReason ?? "N/A"}</p>
                </div>";
            }

            string htmlBottomDetails = $@"
            {referenceSection}

            <div class=""px-14 py-10 text-sm text-neutral-700"">
                <p class=""text-slate-400 italic"">
                    Documento autorizado mediante resolución de Administración Tributaria.<br/>
                    Actividad económica: {invoice.ActivityCode}
                </p>
            </div>

            <footer class=""fixed bottom-0 left-0 bg-slate-100 w-full text-neutral-600 text-center text-xs py-3"">
                Distribuidora Sion
                <span class=""text-slate-300 px-2"">|</span>
                Factura Electrónica - Costa Rica
            </footer>";
            return htmlBottomDetails;
        }
    }
}
